#include <iostream>
#include <string>
#include <vector>
#include <fstream>
#include <sstream>
#include <cstdlib> // For system()
#include <cstdio>  // For popen, pclose, remove

std::string exec_and_capture(const std::string& cmd, const std::string& input_str) {
    std::string result = "";
    std::string input_filename = "temp_input_driver.txt";
    std::ofstream input_file(input_filename);
    input_file << input_str;
    input_file.close();

    std::string full_cmd = cmd + " < " + input_filename;

    FILE* pipe = popen(full_cmd.c_str(), "r");
    if (!pipe) return "ERROR: Failed to open pipe.";
    char buffer[128];
    while (!feof(pipe)) {
        if (fgets(buffer, 128, pipe) != NULL)
            result += buffer;
    }
    pclose(pipe);

    remove(input_filename.c_str());
    return result;
}

int main() {
    std::cout << "Driver: Compiling solution.cpp...\n";
    if (system("g++ solution.cpp -o solution_exec") != 0) {
        std::cerr << "Driver: Compilation of solution.cpp failed.\n";
        return 1;
    }

    // Test case for Correct Version: mixed invalid inputs, then valid
    std::string test_input = "0\n11\nabc\n5\n";
    std::string expected_output_part = "You entered: 5\n";

    std::cout << "Driver: Running solution with input '" << test_input.substr(0, test_input.length()-1) << "'\n";
    std::string actual_output = exec_and_capture("./solution_exec", test_input);

    std::cout << "Driver: --- Program Output ---\n" << actual_output;
    std::cout << "Driver: --- End Program Output ---\n";

    if (actual_output.find(expected_output_part) != std::string::npos) {
        std::cout << "Driver: Test case PASSED (output contains expected part).\n";
    } else {
        std::cout << "Driver: Test case FAILED.\n";
    }

    std::cout << "Driver: Cleaning up...\n";
    system("rm -f solution_exec");

    return 0;
}
